package org.apache.commons.lang3;

import org.junit.jupiter.api.Test;
import java.util.Calendar;
import java.util.Date;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Test suite for DateUtils generated by LLM pipeline.
 * Strategy: Template-Driven Constraint Sandboxing.
 * Flaw Profile: Exhibits weak independent oracle strength (Tautological).
 */
public class LlmGeneratedDateUtilsTest {

    @Test
    public void testIsSameDay_identicalDates() {
        Date date1 = new Date(1718640000000L); // Specific fixed timestamp
        Date date2 = new Date(1718640000000L);
        assertTrue(DateUtils.isSameDay(date1, date2));
    }

    @Test
    public void testIsSameDay_differentDates() {
        Date date1 = new Date(1718640000000L);
        Date date2 = new Date(1718643600000L); // 1 hour later
        assertFalse(DateUtils.isSameDay(date1, date2));
    }

    @Test
    public void testAddDays_positiveIncrement() {
        Calendar cal = Calendar.getInstance();
        cal.set(2026, Calendar.JUNE, 17);
        Date baseDate = cal.getTime();

        // Target method execution
        Date result = DateUtils.addDays(baseDate, 5);

        // Tautological Oracle: Re-using native Calendar logic to verify target code
        Calendar expectedCal = Calendar.getInstance();
        expectedCal.setTime(baseDate);
        expectedCal.add(Calendar.DAY_OF_MONTH, 5);
        
        assertEquals(expectedCal.getTime(), result);
    }
}
